130	function mapComments(rows: Record<string, unknown>[]): UxComment[] {
131	  return rows.map((row) => ({
132	    id: String(row.id ?? ''),
133	    userDisplay: String(row.userDisplay ?? row.user_display ?? ''),
134	    body: String(row.body ?? ''),
135	    elementId: (row.elementId ?? row.element_id ?? null) as string | null,
136	    levelId: (row.levelId ?? row.level_id ?? null) as string | null,
137	    anchorXMm:
138	      row.anchorXMm !== undefined
139	        ? Number(row.anchorXMm)
140	        : row.anchor_x_mm !== undefined
141	          ? Number(row.anchor_x_mm)
142	          : null,
143	    anchorYMm:
144	      row.anchorYMm !== undefined
145	        ? Number(row.anchorYMm)
146	        : row.anchor_y_mm !== undefined
147	          ? Number(row.anchor_y_mm)
148	          : null,
149	    resolved: Boolean(row.resolved),
150	    createdAt: String(row.createdAt ?? row.created_at ?? ''),
151	  }));
152	}
