273	  /* ── Tab helpers (§11.3) ──────────────────────────────────────────── */
274	  const activeTab: ViewTab | null = useMemo(
275	    () =>
276	      tabsState.activeId ? (tabsState.tabs.find((t) => t.id === tabsState.activeId) ?? null) : null,
277	    [tabsState],
278	  );
279	
280	  const handleTabActivate = useCallback(
281	    (id: string) => {
282	      let pendingPlanCamera: ViewportSnapshot['planCamera'] | undefined;
283	
284	      setTabsState((s) => {
285	        if (s.activeId === id) return s;
286	        // Snapshot the outgoing tab's viewport state so it can be restored
287	        // when the user comes back. T-07.
288	        let snapshotted = s;
289	        if (s.activeId) {
290	          const outgoing = s.tabs.find((x) => x.id === s.activeId);
291	          if (outgoing) {
292	            if (outgoing.kind === '3d' || outgoing.kind === 'plan-3d') {
293	              const pose = useBimStore.getState().orbitCameraPoseMm;
294	              if (pose) {
295	                snapshotted = snapshotViewport(snapshotted, s.activeId, {
296	                  ...(outgoing.viewportState ?? {}),
297	                  orbitCameraPoseMm: { eyeMm: pose.position, targetMm: pose.target },
298	                });
299	              }
300	            }
301	            // Snapshot the 2D plan camera for plan tabs (T-07 follow-up).
302	            if (outgoing.kind === 'plan' || outgoing.kind === 'plan-3d') {
303	              const planSnap = planCameraHandleRef.current?.getSnapshot();
304	              if (planSnap) {
305	                snapshotted = snapshotViewport(snapshotted, s.activeId, {
306	                  ...(snapshotted.tabs.find((x) => x.id === s.activeId)?.viewportState ?? {}),
307	                  planCamera: planSnap,
308	                });
309	              }
310	            }
311	          }
312	        }
313	        const next = activateTab(snapshotted, id);
314	        const t = next.tabs.find((x) => x.id === id);
315	        if (!t) return next;
316	        // Keep the store's active level in sync with the active tab's target.
317	        if ((t.kind === 'plan' || t.kind === 'plan-3d') && t.targetId) {
318	          setActiveLevelId(t.targetId);
319	        }
320	        // Restore the incoming tab's 3D camera, if it has one.
321	        const restored = t.viewportState?.orbitCameraPoseMm;
322	        if (restored?.eyeMm && restored.targetMm) {
323	          useBimStore.getState().setOrbitCameraFromViewpointMm({
324	            position: restored.eyeMm,
325	            target: restored.targetMm,
326	            up: { xMm: 0, yMm: 1, zMm: 0 },
327	          });
328	        }
329	        // Capture the incoming plan camera for post-setState apply (plan-to-plan case).
330	        if (t.kind === 'plan' || t.kind === 'plan-3d') {
331	          pendingPlanCamera = t.viewportState?.planCamera;
332	        }
333	        return next;
334	      });
335	
336	      // Apply plan camera to the already-mounted PlanCanvas (plan-to-plan switch).
337	      // For 3D→plan switches, initialCamera prop handles restore at mount time.
338	      if (pendingPlanCamera) {
339	        planCameraHandleRef.current?.applySnapshot(pendingPlanCamera);
340	      }
341	    },
342	    [setActiveLevelId],
343	  );
