368	    const payload = buildSnapshotPayload(snap);
369	    downloadSnapshot(payload);
370	    const next = pushRecentProject(payload);
371	    setRecentProjects(next.map((r) => ({ id: r.id, label: r.label })));
372	  }, []);
373	
374	  const handleRestoreSnapshot = useCallback(
375	    async (file: File): Promise<void> => {
376	      try {
377	        const payload = await readSnapshotFile(file);
