428	  /* ── Semantic command dispatch (from PlanCanvas / Viewport) ────────── */
429	  const onSemanticCommand = useCallback(
430	    async (cmd: Record<string, unknown>): Promise<void> => {
431	      const mid = useBimStore.getState().modelId;
432	      const uid = useBimStore.getState().userId;
433	      if (!mid) return;
434	      try {
435	        const r = await applyCommand(mid, cmd, { userId: uid });
436	        if (r.revision !== undefined) {
437	          hydrateFromSnapshot({
438	            modelId: mid,
439	            revision: r.revision,
440	            elements: r.elements ?? {},
441	            violations: (r.violations ?? []) as Violation[],
442	          });
443	          syncLastLevelElevationPropagationFromApplyResponse(
444	            r as Parameters<typeof syncLastLevelElevationPropagationFromApplyResponse>[0],
445	          );
446	          setUndoDepth((d) => d + 1);
447	        }
448	        setCollaborationConflictQueue(null);
449	      } catch (err) {
450	        if (err instanceof ApiHttpError && err.status === 409) {
451	          console.error('[bim] 409 conflict detail:', err.detail);
452	          setCollaborationConflictQueue(buildCollaborationConflictQueueV1(err.detail));
453	        } else {
454	          setCollaborationConflictQueue(null);
455	          setSeedError(err instanceof Error ? err.message : 'Apply failed');
456	        }
457	      }
458	    },
459	    [hydrateFromSnapshot],
460	  );
461	
462	  /* ── Undo / Redo ────────────────────────────────────────────────────── */
