466	      const uid = useBimStore.getState().userId;
467	      if (!mid) return;
468	      try {
469	        const r = isUndo ? await undoModel(mid, uid) : await redoModel(mid, uid);
470	        if (r.revision !== undefined) {
471	          hydrateFromSnapshot({
472	            modelId: mid,
473	            revision: r.revision,
474	            elements: r.elements ?? {},
475	            violations: (r.violations ?? []) as Violation[],
476	          });
477	          syncLastLevelElevationPropagationFromApplyResponse(
478	            r as Parameters<typeof syncLastLevelElevationPropagationFromApplyResponse>[0],
479	          );
480	          setUndoDepth((d) => Math.max(0, d + (isUndo ? -1 : 1)));
481	        }
482	        // Refresh activity after undo/redo
483	        fetchActivity(mid)
484	          .then((a) => {
485	            const evs = ((a.events ?? []) as Record<string, unknown>[]).map((ev) => ({
486	              id: Number(ev.id),
487	              userId: String(ev.userId ?? ev.user_id ?? ''),
488	              revisionAfter: Number(ev.revisionAfter ?? ev.revision_after ?? 0),
489	              createdAt: String(ev.createdAt ?? ev.created_at ?? ''),
490	              commandTypes: Array.isArray(ev.commandTypes) ? ev.commandTypes.map(String) : [],
491	            }));
492	            setActivity(evs);
493	          })
494	          .catch((err) => console.error('[loadSnapshot] fetchActivity failed', err));
495	        setCollaborationConflictQueue(null);
496	      } catch (err) {
497	        if (err instanceof ApiHttpError && err.status === 409) {
498	          setCollaborationConflictQueue(buildCollaborationConflictQueueV1(err.detail));
499	        } else {
500	          setCollaborationConflictQueue(null);
501	        }
502	      }
503	    },
504	    [hydrateFromSnapshot, setActivity],
505	  );
