507	  /* ── Viewpoint field persistence (3D viewport internal controls) ────── */
508	  const persistViewpointField = useCallback(
509	    async (payload: { elementId: string; key: string; value: string }): Promise<void> => {
510	      const st = useBimStore.getState();
511	      if (!st.activeViewpointId || st.activeViewpointId !== payload.elementId) return;
