519	    const vid = st.activeViewpointId;
520	    if (!vid || st.viewerMode !== 'orbit_3d') return;
521	    const hidden = VIEWER_HIDDEN_KIND_KEYS.filter((k) => st.viewerCategoryHidden[k]);
522	    await onSemanticCommand({
523	      type: 'updateElementProperty',
524	      elementId: vid,
525	      key: 'hiddenSemanticKinds3d',
526	      value: JSON.stringify(hidden),
527	    });
528	  }, [onSemanticCommand]);
