531	    const st = useBimStore.getState();
532	    const vid = st.activeViewpointId;
533	    if (!vid || st.viewerMode !== 'orbit_3d') return;
534	    await onSemanticCommand({
535	      type: 'updateElementProperty',
536	      elementId: vid,
537	      key: 'viewerClipCapElevMm',
538	      value: st.viewerClipElevMm == null ? '' : String(st.viewerClipElevMm),
539	    });
540	    await onSemanticCommand({
541	      type: 'updateElementProperty',
542	      elementId: vid,
543	      key: 'viewerClipFloorElevMm',
544	      value: st.viewerClipFloorElevMm == null ? '' : String(st.viewerClipFloorElevMm),
545	    });
546	  }, [onSemanticCommand]);
