577	        })
578	        .catch((err) => console.error('[insertSeedHouse] fetchComments failed', err));
579	      // Open WebSocket for real-time collaboration
580	      const disableWs =
581	        typeof import.meta.env.VITE_E2E_DISABLE_WS === 'string' &&
582	        ['1', 'true', 'yes'].includes(import.meta.env.VITE_E2E_DISABLE_WS.trim().toLowerCase());
583	      if (!disableWs) {
584	        const p = window.location.protocol === 'https:' ? 'wss' : 'ws';
