706	      const target = event.target as HTMLElement | null;
707	      if (target) {
708	        const tag = target.tagName;
709	        if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;
710	        if (target.isContentEditable) return;
711	      }
712	      const fromMode = modeForHotkey(event.key);
713	      if (fromMode) {
714	        event.preventDefault();
715	        handleModeChange(fromMode);
716	        return;
717	      }
718	      if (event.key === '?') {
719	        event.preventDefault();
720	        setCheatsheetOpen((v) => !v);
721	        return;
722	      }
723	      if ((event.key === 'k' || event.key === 'K') && (event.metaKey || event.ctrlKey)) {
724	        event.preventDefault();
725	        setPaletteOpen((v) => !v);
726	        return;
727	      }
728	      // Tab cycling — Ctrl/⌘+Tab forward, Ctrl/⌘+Shift+Tab back.
729	      if (event.key === 'Tab' && (event.metaKey || event.ctrlKey)) {
730	        event.preventDefault();
