263	    if (pr) {
264	      if (pr.lineWeightFactor != null && Number.isFinite(pr.lineWeightFactor)) {
265	        f = pr.lineWeightFactor;
266	        wSrc = 'plan_view';
267	        wDef = false;
268	      }
269	      if (pr.linePatternToken) {
270	        pat = pr.linePatternToken;
271	        pSrc = 'plan_view';
272	        pDef = false;
273	      }
274	    }
275	    out[key] = {
276	      lineWeightFactor: Math.round(f * 10000) / 10000,
277	      linePatternToken: pat,
278	      lineWeightSource: wSrc,
279	      linePatternSource: pSrc,
280	      lineWeightIsDefaulted: wDef,
281	      linePatternIsDefaulted: pDef,
282	    };
283	  }
284	  return out;
