878	): OrbitViewCutawayStyleToken {
879	  if (vp.mode !== 'orbit_3d') return 'none';
880	  const persisted = viewpointPersistedCutawayStyle(vp);
881	  if (persisted !== undefined) return persisted;
882	  const hasCap = vp.viewerClipCapElevMm != null && Number.isFinite(vp.viewerClipCapElevMm);
883	  const hasFloor = vp.viewerClipFloorElevMm != null && Number.isFinite(vp.viewerClipFloorElevMm);
884	  if (hasCap && hasFloor) return 'box';
885	  if (hasCap) return 'cap';
886	  if (hasFloor) return 'floor';
887	  return 'none';
888	}
889	
890	/** Human-readable cutaway / section-box style (explicit `cutawayStyle` when set, else clip-derived). */
891	export function viewpointOrbit3dCutawayStyleLabel(
892	  vp: Extract<Element, { kind: 'viewpoint' }>,
893	): string {
894	  const t = viewpointOrbit3dCutawayStyleToken(vp);
895	  switch (t) {
896	    case 'none':
897	      return 'No elevation clip';
898	    case 'cap':
899	      return 'Cap clip only';
900	    case 'floor':
901	      return 'Floor clip only';
902	    case 'box':
903	      return 'Box clip (cap + floor)';
904	    default: {
905	      const _exhaustive: never = t;
906	      return _exhaustive;
907	    }
908	  }
909	}
910	
911	/** Hidden 3D semantic kinds (shown as “categories” in UX copy). */
912	export function viewpointOrbit3dHiddenKindsReadout(
913	  vp: Extract<Element, { kind: 'viewpoint' }>,
914	): string {
915	  if (vp.mode !== 'orbit_3d') return '—';
916	  const kinds = vp.hiddenSemanticKinds3d;
917	  if (kinds == null || kinds.length === 0) return '—';
918	  const joined = kinds.join(', ');
919	  if (joined.length <= ORBIT_HIDDEN_KINDS_MAX_CHARS) return `${kinds.length}: ${joined}`;
920	  return `${kinds.length}: ${joined.slice(0, ORBIT_HIDDEN_KINDS_MAX_CHARS - 1)}…`;
921	}
922	
923	export function viewpointOrbit3dEvidenceLine(vp: Extract<Element, { kind: 'viewpoint' }>): string {
924	  if (vp.mode !== 'orbit_3d') return '';
925	  const cap = vp.viewerClipCapElevMm;
926	  const floor = vp.viewerClipFloorElevMm;
927	  const hid = vp.hiddenSemanticKinds3d?.length ?? 0;
928	  const capS = cap == null ? '∅' : String(cap);
929	  const floorS = floor == null ? '∅' : String(floor);
930	  const cut = viewpointOrbit3dCutawayStyleToken(vp);
931	  const sbEnabled = vp.sectionBoxEnabled;
932	  const sbMin = vp.sectionBoxMinMm;
933	  const sbMax = vp.sectionBoxMaxMm;
934	  let sbTok = '';
935	  if (sbEnabled != null) {
936	    if (sbEnabled && sbMin != null && sbMax != null) {
937	      sbTok = ` · sbox[${sbMin.xMm},${sbMin.yMm},${sbMin.zMm}→${sbMax.xMm},${sbMax.yMm},${sbMax.zMm}]`;
938	    } else {
939	      sbTok = ` · sbox:${sbEnabled ? 'on' : 'off'}`;
940	    }
941	  }
942	  return `clip cap ${capS} · floor ${floorS} · ${hid} hid · cut:${cut}${sbTok}`;
943	}
944	
945	/** Deterministic inheritance readout for Workspace Inspector (mirrors resolver math). */
946	
947	export function planViewInheritanceSummaryLines(
948	  elementsById: Record<string, Element>,
949	  planViewId: string,
950	): string[] {
951	  const el = elementsById[planViewId];
952	  if (!el || el.kind !== 'plan_view') return [];
953	
954	  const g = resolvePlanGraphicHints(elementsById, planViewId);
955	  const a = resolvePlanAnnotationHints(elementsById, planViewId);
956	  const tmplId = el.viewTemplateId;
957	  const tmpl =
958	    tmplId && elementsById[tmplId]?.kind === 'view_template' ? elementsById[tmplId] : undefined;
959	
960	  const effDetail = g?.detailLevel ?? 'medium';
961	  const effFill = g?.roomFillOpacityScale ?? 1;
962	  const pvDetail =
963	    el.planDetailLevel === undefined || el.planDetailLevel === null
964	      ? 'inherit'
965	      : el.planDetailLevel;
966	  const pvFill =
967	    el.planRoomFillOpacityScale == null ? 'inherit' : String(el.planRoomFillOpacityScale);
968	
969	  const vtDetail =
970	    tmpl == null ? '—' : tmpl.planDetailLevel == null ? 'inherit→medium' : tmpl.planDetailLevel;
971	  const vtFill = tmpl == null ? '—' : String(tmpl.planRoomFillOpacityScale);
972	
973	  const pvOpening =
974	    el.planShowOpeningTags === undefined ? 'inherit' : el.planShowOpeningTags ? 'on' : 'off';
975	  const pvLabels =
976	    el.planShowRoomLabels === undefined ? 'inherit' : el.planShowRoomLabels ? 'on' : 'off';
977	
978	  const pvOpenRef =
979	    el.planOpeningTagStyleId === undefined || el.planOpeningTagStyleId === null
980	      ? 'inherit'
981	      : el.planOpeningTagStyleId;
982	  const pvRoomRef =
983	    el.planRoomTagStyleId === undefined || el.planRoomTagStyleId === null
984	      ? 'inherit'
985	      : el.planRoomTagStyleId;
986	
987	  const effOpen = resolvePlanTagStyleLane(elementsById, planViewId, 'opening');
988	  const effRoom = resolvePlanTagStyleLane(elementsById, planViewId, 'room');
989	
990	  return [
991	    `Graphics: detail=${effDetail}, lineWeight×=${g?.lineWeightScale ?? 1}, roomFill=${effFill}`,
992	    `Stored plan_view: detail=${pvDetail}, roomFill=${pvFill}`,
993	    `Template: detail=${vtDetail}, roomFill=${vtFill}`,
994	    `Opening tags: effective=${a.openingTagsVisible ? 'on' : 'off'}; plan_view=${pvOpening}; template=${tmpl ? (tmpl.planShowOpeningTags ? 'on' : 'off') : '—'}`,
995	    `Room labels: effective=${a.roomLabelsVisible ? 'on' : 'off'}; plan_view=${pvLabels}; template=${tmpl ? (tmpl.planShowRoomLabels ? 'on' : 'off') : '—'}`,
996	    `Opening tag style: effective=${formatPlanTagStyleMatrixCell(effOpen)}; plan_view.stored=${pvOpenRef === 'inherit' ? 'inherit' : String(pvOpenRef)}; template.default=${tmpl?.defaultPlanOpeningTagStyleId ?? '—'}`,
997	    `Room tag style: effective=${formatPlanTagStyleMatrixCell(effRoom)}; plan_view.stored=${pvRoomRef === 'inherit' ? 'inherit' : String(pvRoomRef)}; template.default=${tmpl?.defaultPlanRoomTagStyleId ?? '—'}`,
998	  ];
999	}
