97	function coerceEvidenceRefs(rawUnknown: unknown): EvidenceRef[] {
98	  if (!Array.isArray(rawUnknown)) return [];
99	  const refs: EvidenceRef[] = [];
100	  for (const item of rawUnknown) {
101	    if (typeof item !== 'object' || item === null) continue;
102	    const o = item as Record<string, unknown>;
103	    const kindRaw = o.kind;
104	    if (typeof kindRaw !== 'string' || !_EVIDENCE_REF_KINDS.has(kindRaw as EvidenceRefKind)) {
105	      continue;
106	    }
107	    const kind = kindRaw as EvidenceRefKind;
108	    const sheetId =
109	      typeof (o.sheetId ?? o.sheet_id) === 'string' ? String(o.sheetId ?? o.sheet_id) : undefined;
110	    const viewpointId =
111	      typeof (o.viewpointId ?? o.viewpoint_id) === 'string'
112	        ? String(o.viewpointId ?? o.viewpoint_id)
113	        : undefined;
114	    const planViewId =
115	      typeof (o.planViewId ?? o.plan_view_id) === 'string'
116	        ? String(o.planViewId ?? o.plan_view_id)
117	        : undefined;
118	    const sectionCutId =
119	      typeof (o.sectionCutId ?? o.section_cut_id) === 'string'
120	        ? String(o.sectionCutId ?? o.section_cut_id)
121	        : undefined;
122	    const pngBasename =
123	      typeof (o.pngBasename ?? o.png_basename) === 'string'
124	        ? String(o.pngBasename ?? o.png_basename)
125	        : undefined;
126	    refs.push({
127	      kind,
128	      ...(sheetId !== undefined ? { sheetId } : {}),
129	      ...(viewpointId !== undefined ? { viewpointId } : {}),
130	      ...(planViewId !== undefined ? { planViewId } : {}),
131	      ...(sectionCutId !== undefined ? { sectionCutId } : {}),
132	      ...(pngBasename !== undefined ? { pngBasename } : {}),
133	    });
134	  }
135	  refs.sort((a, b) => {
136	    const ak = `${a.kind}|${a.sheetId ?? ''}|${a.viewpointId ?? ''}|${a.planViewId ?? ''}|${a.sectionCutId ?? ''}|${a.pngBasename ?? ''}`;
137	    const bk = `${b.kind}|${b.sheetId ?? ''}|${b.viewpointId ?? ''}|${b.planViewId ?? ''}|${b.sectionCutId ?? ''}|${b.pngBasename ?? ''}`;
138	    return ak.localeCompare(bk);
139	  });
140	  return refs;
141	}
