143	function readPlanViewBoolOverride(raw: unknown): boolean | undefined {
144	  if (raw === null || raw === undefined) return undefined;
145	  if (typeof raw === 'boolean') return raw;
146	  if (typeof raw === 'string') {
147	    const s = raw.trim().toLowerCase();
148	    if (s === '') return undefined;
149	    if (s === 'true' || s === '1') return true;
150	    if (s === 'false' || s === '0') return false;
151	  }
152	  return undefined;
153	}
